-- Car2Buy — migrate existing inventory into public.cars (new + used)
-- Run once in Supabase SQL Editor.

-- 1) add columns used by the split (safe to re-run)
alter table public.cars add column if not exists condition text not null default 'new';
alter table public.cars add column if not exists sort_order integer;

-- 2) avoid duplicates if re-run: clear rows we previously migrated
delete from public.cars where (extra->>'migrated') = 'true';

